// ═══════════════════════════════════════════════════════
// WriteUP UPGC — Beginner Content (21 days)
// ═══════════════════════════════════════════════════════

export const GRAMMAR_BEGINNER = [
  {id:"gb01",title:"Present Simple",q:"She ___ to school every day.",opts:["go","goes","is going","has gone"],ans:1,exp:"Present simple describes habits, routines, and permanent facts. 'Every day' is a classic signal word for a repeated action. In the third person singular (he/she/it), always add -s: she goes, he works. English requires BOTH the pronoun AND the verb to change — unlike French where the verb ending alone carries person information.",tip:"Signal words: always, usually, often, sometimes, rarely, never, every day/week. In academic writing, use present simple to state facts ('Research shows that...') and describe authors ('Achebe argues that...'). NEVER use present continuous for habits: 'She is going to school every day' is incorrect."},
  {id:"gb02",title:"Articles A/An",q:"She wants to be ___ engineer when she grows up.",opts:["a","an","the","—"],ans:1,exp:"'An' is used before vowel SOUNDS, not vowel letters. 'Engineer' begins with the sound /e/ — a vowel sound — so we use 'an'. Careful: 'university' starts with 'u' but sounds like /ju/ (a consonant sound), so it takes 'a university'. Similarly: 'an hour' (the h is silent) but 'a hotel' (the h is pronounced). Always say the word aloud first to check.",tip:"The rule is about SOUND, not spelling. An apple, an hour, an umbrella are correct. But: a university, a one-way street (one = /w/ consonant sound). Academic examples: 'an MA degree' (M is pronounced 'em' — vowel sound), 'an UPGC student'. This error frequently appears in formal emails and reports from French speakers."},
  {id:"gb03",title:"Past Simple",q:"Yesterday, he ___ his homework before dinner.",opts:["finish","finishes","finished","has finished"],ans:2,exp:"'Yesterday' places the action in a completed, finished past — so we use past simple. Regular past simple adds -ed: finish-finished, arrive-arrived. Note spelling rules: verbs ending in -e just add -d; verbs ending in consonant-y change to -ied (study-studied). Past simple is for events with a clear start and end in the past, with no connection to the present.",tip:"Past simple signal words: yesterday, last week, last year, in 2015, ago, when I was young. Do NOT use past simple with 'since', 'already', 'just', 'ever', or 'recently' — these require present perfect. Academic usage: 'Smith (2019) found that...', 'The government introduced the policy in 2021', 'Participants completed the questionnaire last January.'"},
  {id:"gb04",title:"Plurals",q:"There are three ___ in the classroom.",opts:["child","childs","children","childrens"],ans:2,exp:"'Child' has an irregular plural: children. The word changes its vowel — you cannot add -s to irregular plurals. This is directly influenced by French where most nouns form plurals with -s ('les enfants'), but English has a separate category of irregular forms. Writing 'childs' or 'childrens' is a very clear error that marks the writer as a beginner — these forms must be memorised.",tip:"Essential irregular plurals: child-children, man-men, woman-women, person-people, foot-feet, tooth-teeth, mouse-mice, sheep-sheep (no change), fish-fish. Academic: 'The data show...' (data = plural of datum), 'The criteria are...' (plural of criterion), 'The phenomena suggest...' (plural of phenomenon). These errors appear frequently in student essays and should be eliminated."},
  {id:"gb05",title:"Prepositions of Time",q:"The exam starts ___ 9 o'clock ___ Monday morning.",opts:["at / on","in / at","on / in","at / in"],ans:0,exp:"English uses three precise time prepositions that cannot be interchanged. AT is for exact clock times (a specific point). ON is for specific days and dates. IN is for months, years, seasons, and longer periods. These correspond roughly to French 'a', 'le/la', and 'en' — but the mapping is not always exact. Memorise these as fixed combinations rather than trying to translate from French.",tip:"AT + time: at 9am, at noon, at midnight, at night. ON + day or date: on Monday, on 15 March, on Christmas Day. IN + period: in January, in 2024, in winter, in the morning (British English). Academic exceptions: 'at the end of the chapter', 'in the introduction', 'on page 42', 'at university' (British), 'in the first semester'."},
  {id:"gb06",title:"There is / There are",q:"___ many students in the library today.",opts:["There is","There are","It is","They are"],ans:1,exp:"'There is/are' announces the existence of something in a context. The verb agrees with the noun that follows it, not with 'there'. 'Students' is plural, so we use 'there are'. French 'il y a' is invariable — it works for both singular and plural — which directly causes the error 'there is many students'. Always identify the noun after the verb to determine whether to use is or are.",tip:"There IS + singular or uncountable: 'There is a library on campus.' There ARE + plural: 'There are 500 students.' Contracted form in speech: 'There's a problem.' In academic writing: 'There are three main arguments...', 'There is considerable debate about...', 'There is no evidence to suggest that...' This construction is very common in academic introductions."},
  {id:"gb07",title:"Comparative Adjectives",q:"English is ___ than mathematics for some students.",opts:["more easy","easyer","easier","most easy"],ans:2,exp:"Short adjectives (one syllable, or two syllables ending in -y) form comparatives with -er, never with 'more'. 'Easy' ends in -y, so change -y to -i then add -er: easy-easier. 'More easy' is the direct transfer of French 'plus facile' into English, but this is grammatically incorrect. Longer adjectives (three or more syllables) use 'more': more important, more significant.",tip:"SHORT adjectives (add -er): fast-faster, hard-harder, easy-easier, big-bigger (double consonant), close-closer (drop -e). LONG adjectives (use more): more important, more significant, more complex. IRREGULAR: good-better, bad-worse, far-farther. Academic: 'a more nuanced argument', 'a stronger methodology', 'greater accuracy', 'higher validity'. These comparative forms are used constantly in academic comparisons."},
  {id:"gb08",title:"Can / Cannot",q:"She ___ speak three languages fluently.",opts:["can","cans","is can","does can"],ans:0,exp:"'Can' is a modal verb with special grammar rules. It never takes -s in the third person (she can, NOT she cans), it is never followed by 'to' (can speak, NOT can to speak), and it never combines with 'does' in questions (Can she speak? NOT Does she can?). French 'elle peut parler' tempts speakers to add -s, but English modals are completely invariable in form.",tip:"All modal verbs: can, could, will, would, shall, should, may, might, must. Rule: modal + BASE VERB, no exceptions (except 'ought to' which always includes 'to'). Negatives: cannot/can't, will not/won't, must not/mustn't, should not/shouldn't. Academic: 'This policy may have unintended consequences.', 'The results cannot be generalised to other contexts.', 'Researchers should consider alternative explanations.'"},
  {id:"gb09",title:"Present Continuous",q:"Look! The students ___ a group project right now.",opts:["do","does","are doing","is doing"],ans:2,exp:"Present continuous describes actions in progress at the exact moment of speaking or around the current period. 'Right now' is the clearest possible signal for this tense. Structure: am/is/are + verb-ing. For 'students' (plural subject), the auxiliary is 'are'. Key distinction: 'Students study English' (habit, present simple) vs 'Students are studying English' (right now, this moment). French uses one present form for both — English uses two completely separate tenses.",tip:"Signals for present continuous: right now, at the moment, currently, today, this week. STATIVE VERBS cannot take -ing: know, understand, believe, prefer, seem, contain, belong. Say 'I understand' NOT 'I am understanding'. Academic uses: 'Researchers are increasingly focusing on...', 'The situation is rapidly changing...', 'Evidence is accumulating that...' These signal ongoing developments."},
  {id:"gb10",title:"Possessive Adjectives",q:"Every student must bring ___ own dictionary to the exam.",opts:["their","there","they're","its"],ans:0,exp:"'Their' is the possessive adjective for 'they' or any plural noun — it shows ownership. Do not confuse with 'there' (indicating a location or existence: 'there is a library') or 'they're' (contraction of they are: 'they're studying'). All three words are pronounced identically in English — this confusion only exists in written form and is one of the most common spelling errors in academic work.",tip:"Memory trick: THEIR contains 'heir' (someone who inherits possessions) — a signal for ownership. THERE contains 'here' — a signal for location. THEY'RE = they are (test by expanding: if 'they are' makes sense, use they're). Academic: 'Each student should develop their own argument.' Using 'their' as a singular neutral pronoun is now widely accepted in formal academic English."},
  {id:"gb11",title:"Future with Will",q:"I think it ___ rain tomorrow, so bring an umbrella.",opts:["will","is","was","has"],ans:0,exp:"'Will' is used for predictions based on knowledge or expectation, for promises, and for spontaneous decisions made at the moment of speaking. 'I think it will rain' is a personal prediction. This corresponds to the French future simple ('il pleuvra'), but English has several future forms and using the right one adds significant precision and naturalness to your writing.",tip:"WILL for: predictions ('It will rain'), promises ('I will submit the essay by Friday'), instant decisions ('I'll take the coffee'). GOING TO for: pre-decided plans ('I'm going to study tonight'), predictions based on visible evidence ('Look at those clouds — it's going to rain'). Academic: 'This paper will argue that...', 'The following section will examine three key themes.'"},
  {id:"gb12",title:"Countable Nouns",q:"She bought ___ apple and ___ banana from the market.",opts:["a / a","an / a","a / an","an / an"],ans:1,exp:"The a/an rule depends entirely on pronunciation — not spelling. 'Apple' starts with the vowel sound /ae/ so we use 'an'. 'Banana' starts with the consonant sound /b/ so we use 'a'. When a word begins with a vowel letter but a consonant sound (like 'university' = /j/), use 'a'. When a word begins with a consonant letter but a vowel sound (like 'hour' — the h is silent), use 'an'. Always test by saying the word aloud.",tip:"Test method: say the word. Vowel SOUND: use an. Consonant SOUND: use a. Tricky cases: a university (u = /j/ consonant sound), an hour (h is silent, vowel sound), a hotel (h is pronounced), an MP (em-pee, starts with vowel sound 'em'), an X-ray (ex-ray, starts with vowel sound). Common in academic titles: 'a BA degree', 'an MA degree', 'a PhD', 'an MSc'."},
  {id:"gb13",title:"Subject-Verb Agreement",q:"The quality of the essays ___ improved this semester.",opts:["have","has","are","were"],ans:1,exp:"The verb must agree with the HEAD NOUN of the subject — not the nearest noun. The head noun here is 'quality' (singular), not 'essays'. The phrase 'of the essays' is a modifier that does not affect the agreement of the verb. Remove it mentally: 'The quality has improved.' This error — agreeing with the nearest noun — is called an attraction error, and it is very common in complex noun phrases.",tip:"Practise identifying subjects: 'The list of requirements IS complete' (list = singular). 'A number of students ARE present' (students = plural). 'The number of students IS increasing' (the number = singular). Academic: 'Each student submits their essay.' 'The majority of participants AGREE...' vs 'A majority of participants AGREE...' — both acceptable. Always ask: what is actually performing the action?"},
  {id:"gb14",title:"Adverbs of Frequency",q:"She ___ forgets to submit her assignments on time.",opts:["never","always never","not always","ever"],ans:0,exp:"'Never' is already a negative adverb of frequency meaning 0% of the time. Adding 'don't' creates an ungrammatical double negative — English only allows one negative element per clause. French uses two negative words ('ne...jamais', 'ne...rien'), but English requires only one negative. Position rule for frequency adverbs: go BEFORE the main verb but AFTER the verb 'to be'.",tip:"Frequency scale: always (100%) - usually - often - sometimes - occasionally - rarely/seldom - never (0%). Position: BEFORE main verb ('She never forgets'), AFTER to be ('She is always punctual'). Academic: 'Such outcomes are rarely documented.', 'This approach has never been systematically tested.', 'Researchers seldom account for this variable.' Precision in frequency language strengthens academic arguments."},
  {id:"gb15",title:"Question Formation",q:"___ does the library close on weekends?",opts:["When","What time","How","Which time"],ans:1,exp:"'What time' asks for a specific hour or time on the clock and requires an answer like 'at 6pm' or 'at 9am'. 'When' asks about a time period or moment more broadly and can be answered with a date, a period, or a moment in a sequence. Since the question is about the specific closing hour of the library, 'What time' is the precise and natural choice here.",tip:"Question words for time: WHAT TIME = specific clock time. WHEN = broader time, period, or moment. HOW LONG = duration. HOW OFTEN = frequency. Academic examples: 'At what point does learning become permanent?' 'When did researchers first propose this theory?' 'How long does the intervention last?' 'How often do such events occur?' Precise question language reflects precise analytical thinking."},
  {id:"gb16",title:"Much / Many",q:"There isn't ___ time left before the deadline.",opts:["many","much","a lot","some"],ans:1,exp:"'Time' in this sentence refers to an abstract, uncountable quantity — not to individual units that can be counted (hours, minutes). With uncountable nouns in negative and question sentences, use 'much'. 'Many' is reserved exclusively for countable nouns (things you can count individually). French 'beaucoup de' works for both countable and uncountable nouns, which directly causes the error 'many time'.",tip:"UNCOUNTABLE nouns (use much/little/a lot of): time, money, information, advice, knowledge, evidence, research, progress, furniture, equipment, luggage, news. COUNTABLE nouns (use many/few/a number of): students, ideas, books, problems, experiments, findings. Academic: 'There is little evidence to support this claim.', 'Much research has focused on this issue.', 'Few studies have systematically examined this variable.'"},
  {id:"gb17",title:"Imperatives",q:"___ quiet in the library, please.",opts:["Be","Are","Is","Being"],ans:0,exp:"Imperative sentences use the base verb with no subject and no auxiliary verb. They can be positive ('Be quiet', 'Open your books') or negative ('Don't talk', 'Never use informal language'). In formal English, bare imperatives can sound rude or abrupt — 'please' softens them, and restructuring as a question ('Could you please be quiet?') makes them even more polite and professional.",tip:"Academic imperatives appear in instructions and signposting: 'Consider the following.', 'Note that the data are from 2021.', 'Refer to Table 2.', 'See Smith (2019) for a full discussion.' These are standard. Do NOT use imperatives to command the reader in an argument: 'Believe that climate change is real' is wrong. Use instead: 'It is clear that...' or 'The evidence indicates that...'"},
  {id:"gb18",title:"Conjunctions",q:"She studied hard ___ she passed the exam easily.",opts:["so","but","although","however"],ans:0,exp:"'So' signals a consequence or result: the first clause is the cause, and the second clause is the effect. 'She studied hard' is the cause; 'she passed easily' is the result. A comma typically precedes 'so' when joining two independent clauses. Other connectors for result: 'therefore' (more formal), 'consequently' (very formal), 'as a result' (neutral). Choosing the right connector demonstrates logical precision.",tip:"Result connectors: so (informal), therefore (formal, begins main clause), consequently (formal), as a result (neutral). Contrast connectors: but, however, nevertheless, yet, although, even though, despite. Reason connectors: because, since, as, given that. Academic writing: prefer 'therefore', 'consequently', 'as a result' over 'so'. Never begin a formal sentence with 'So' — use 'Therefore' or 'Consequently'."},
  {id:"gb19",title:"Possessive 's",q:"This is ___ book — she left it on the desk.",opts:["Maria's","Marias","the Maria","of Maria"],ans:0,exp:"Possessive 's shows that something belongs to or is associated with a person or named entity. 'Maria's book' is more natural in English than 'the book of Maria', which sounds translated from French or Latin. For plural nouns already ending in -s, add only an apostrophe after the -s: 'the students' essays', 'the researchers' findings'. For singular nouns ending in -s: 'James's research' or 'James' research' — both are acceptable in academic writing.",tip:"Rule: singular possessor: add 's — the teacher's desk, the government's policy. Plural possessor ending in -s: add only ' — the students' results, the researchers' findings. Academic: 'Achebe's narrative perspective', 'Smith's (2020) findings', 'UPGC's English programme'. Avoid using possessive 's with inanimate objects in very formal writing: prefer 'the structure of the essay' over 'the essay's structure', though both are now acceptable."},
  {id:"gb20",title:"Some / Any",q:"Do you have ___ questions about the assignment?",opts:["some","any","no","every"],ans:1,exp:"'Any' is standard in direct questions and negative sentences. 'Some' is used in positive statements and in questions that offer something or expect a positive answer. 'Do you have any questions?' is a neutral question. 'Would you like some help?' is an offer, anticipating that the person might want it. In formal academic writing, this distinction affects the tone and implied expectation of your questions.",tip:"SOME in: positive statements ('I have some evidence'), offers ('Would you like some feedback?'), requests expecting yes ('Can I have some time?'). ANY in: neutral questions ('Do you have any sources?'), negative sentences ('There is no significant difference.' or 'There is not any significant difference.'). Academic: 'Some researchers argue... while others contend...', 'Do you have any concerns about the methodology?'"},
  {id:"gb21",title:"Verb To Be",q:"The results of the test ___ announced yesterday.",opts:["was","were","is","are"],ans:1,exp:"'Results' is a countable plural noun, so the past tense of 'to be' must be 'were' (not 'was'). This sentence also demonstrates passive voice: results did not announce themselves — someone else did it. Passive voice (was/were + past participle) focuses attention on what was done rather than who did it, making it extremely common in academic and scientific writing where objectivity is valued.",tip:"Passive structure: was/were + past participle. 'The data were collected.', 'Three experiments were conducted.', 'The results were published in 2023.' Use passive when the agent is unknown or unimportant, or when objectivity is needed: 'It was found that X increases Y.' Modern academic style also accepts active voice for clarity: 'We found that X increases Y.' Both are now acceptable in most universities and journals."},
];

export const VOCAB_BEGINNER = [
  {id:"vb01",word:"Improve",ph:"/ɪmˈpruːv/",fr:"Améliorer",pos:"verb",def:"To make something better than it was before.",ex:"Students should read every day to ___ their English.",opts:["improve","ignore","reduce","forget"],ans:0,tip:"Think of 'prove' inside improve — you prove you're better."},
  {id:"vb02",word:"Explain",ph:"/ɪkˈspleɪn/",fr:"Expliquer",pos:"verb",def:"To make something clear by describing it in detail.",ex:"The teacher will ___ the grammar rule again.",opts:["explain","complain","remain","obtain"],ans:0,tip:"Ex + plain = make it plain (clear). To explain = to make plain."},
  {id:"vb03",word:"Describe",ph:"/dɪˈskraɪb/",fr:"Décrire",pos:"verb",def:"To say what something or someone is like.",ex:"Can you ___ what happened in the first paragraph?",opts:["describe","subscribe","prescribe","inscribe"],ans:0,tip:"De + scribe (write). To describe = to write about in detail."},
  {id:"vb04",word:"Compare",ph:"/kəmˈpeər/",fr:"Comparer",pos:"verb",def:"To examine similarities and differences between things.",ex:"The essay asks you to ___ two education systems.",opts:["compare","prepare","repair","despair"],ans:0,tip:"Com (together) + pare (equal). To compare = to put side by side."},
  {id:"vb05",word:"Suggest",ph:"/səˈdʒest/",fr:"Suggérer",pos:"verb",def:"To put forward an idea for consideration.",ex:"The report ___ that more libraries are needed.",opts:["suggest","digest","contest","protest"],ans:0,tip:"Suggest sounds like 'subject' — you put a subject forward for others to think about."},
  {id:"vb06",word:"Support",ph:"/səˈpɔːt/",fr:"Soutenir",pos:"verb/noun",def:"To give help or show agreement with something.",ex:"Every argument needs evidence to ___ it.",opts:["support","report","transport","export"],ans:0,tip:"Sub + port (carry). To support = to carry something up from below."},
  {id:"vb07",word:"Develop",ph:"/dɪˈveləp/",fr:"Développer",pos:"verb",def:"To grow or cause something to grow and become more advanced.",ex:"Reading helps students ___ their vocabulary.",opts:["develop","envelope","overlap","relapse"],ans:0,tip:"Think of a photo developing — it gradually becomes clearer and more complete."},
  {id:"vb08",word:"Include",ph:"/ɪnˈkluːd/",fr:"Inclure",pos:"verb",def:"To make something part of a whole.",ex:"Your essay should ___ an introduction and a conclusion.",opts:["include","exclude","conclude","preclude"],ans:0,tip:"In + clude (close). To include = to close something inside a group."},
  {id:"vb09",word:"Require",ph:"/rɪˈkwaɪər/",fr:"Nécessiter",pos:"verb",def:"To need something as necessary or essential.",ex:"This assignment ___ at least 300 words.",opts:["require","inquire","acquire","retire"],ans:0,tip:"Re + quire (seek). To require = to seek again and again — it's essential."},
  {id:"vb10",word:"Achieve",ph:"/əˈtʃiːv/",fr:"Atteindre/Réaliser",pos:"verb",def:"To successfully reach a goal after effort.",ex:"Hard work helps students ___ their academic goals.",opts:["achieve","believe","retrieve","conceive"],ans:0,tip:"A + chieve (chief). To achieve = to become the chief — to reach the top."},
  {id:"vb11",word:"Provide",ph:"/prəˈvaɪd/",fr:"Fournir",pos:"verb",def:"To make something available for someone to use.",ex:"The university ___ free internet access to all students.",opts:["provide","divide","decide","reside"],ans:0,tip:"Pro (forward) + vide (see). To provide = to put something forward for use."},
  {id:"vb12",word:"Increase",ph:"/ɪnˈkriːs/",fr:"Augmenter",pos:"verb",def:"To become or make something larger in amount.",ex:"The number of students who pass has ___ this year.",opts:["increased","decreased","released","pleased"],ans:0,tip:"In + crease (grow). To increase = to grow inward/upward."},
  {id:"vb13",word:"Reduce",ph:"/rɪˈdjuːs/",fr:"Réduire",pos:"verb",def:"To make something smaller or less in amount.",ex:"Schools can ___ failure rates by providing extra help.",opts:["reduce","produce","introduce","deduce"],ans:0,tip:"Re + duce (lead). To reduce = to lead back down to a smaller amount."},
  {id:"vb14",word:"Result",ph:"/rɪˈzʌlt/",fr:"Résultat",pos:"noun/verb",def:"The outcome or consequence of an action.",ex:"Poor preparation often ___ in failure.",opts:["results","resists","consists","persists"],ans:0,tip:"Result from = caused by. Result in = leads to. These prepositions matter!"},
  {id:"vb15",word:"Important",ph:"/ɪmˈpɔːtənt/",fr:"Important",pos:"adjective",def:"Having great significance or effect.",ex:"It is ___ to read the instructions before starting.",opts:["important","impotent","impatient","impartial"],ans:0,tip:"Import + ant. Something imported has value — so does something important."},
  {id:"vb16",word:"Difficult",ph:"/ˈdɪfɪkəlt/",fr:"Difficile",pos:"adjective",def:"Not easy; requiring effort or skill.",ex:"Writing academic essays can be ___ at first.",opts:["difficult","different","deficient","diligent"],ans:0,tip:"Dif + ficult. Think of 'deficit' — something missing that makes things hard."},
  {id:"vb17",word:"Necessary",ph:"/ˈnesəsəri/",fr:"Nécessaire",pos:"adjective",def:"Needed; that must be done or had.",ex:"It is ___ to cite your sources in an academic essay.",opts:["necessary","accessory","secondary","ordinary"],ans:0,tip:"Never Eat Cake, Eat Salad Sandwiches And Remain Young — spell NECESSARY."},
  {id:"vb18",word:"Possible",ph:"/ˈpɒsɪbl/",fr:"Possible",pos:"adjective",def:"Able to be done or to happen.",ex:"With practice, it is ___ to improve your writing quickly.",opts:["possible","probable","portable","potable"],ans:0,tip:"Poss + ible. Think of 'possess' — you can possess the ability to do it."},
  {id:"vb19",word:"Continue",ph:"/kənˈtɪnjuː/",fr:"Continuer",pos:"verb",def:"To keep doing something without stopping.",ex:"Students must ___ practising even after the exam.",opts:["continue","contribute","constitute","contaminate"],ans:0,tip:"Con + tinue (hold). To continue = to keep holding on to what you're doing."},
  {id:"vb20",word:"Problem",ph:"/ˈprɒbləm/",fr:"Problème",pos:"noun",def:"A situation that is difficult to deal with.",ex:"Lack of reading is a major ___ for many students.",opts:["problem","program","process","protest"],ans:0,tip:"Greek: problema = something thrown forward as a challenge to solve."},
  {id:"vb21",word:"Solution",ph:"/səˈluːʃən/",fr:"Solution",pos:"noun",def:"A way of solving a problem.",ex:"Education is the best ___ to poverty.",opts:["solution","pollution","evolution","revolution"],ans:0,tip:"Solve → solution. The act of solving creates a solution."},
];

export const READING_BEGINNER = [
  {id:"rb01",title:"Why Education Matters",topic:"Education",passage:"Education is one of the most important things in a person's life. When people go to school, they learn to read, write, and think clearly. These skills help them in every part of their lives.\n\nIn many African countries, the number of children going to school has increased in recent years. However, many students still drop out before finishing secondary school. The main reasons are poverty, long distances to school, and lack of teachers.\n\nStudies show that every year a child spends in school increases their future income by about 10%. This means that education is not only good for the individual — it is also good for the whole country.",gloss:[{w:"drop out",d:"to leave school before finishing"},{w:"income",d:"money earned from work"},{w:"individual",d:"a single person"}],qs:[{q:"What do children learn at school?",opts:["Only mathematics","To read, write, and think clearly","Only English","To cook and clean"],ans:1},{q:"Why do students drop out?",opts:["They are lazy","Poverty, distance, and lack of teachers","They prefer to work","Schools are too easy"],ans:1},{q:"How much does each school year increase future income?",opts:["5%","20%","10%","50%"],ans:2}]},
  {id:"rb02",title:"Water and Health",topic:"Health",passage:"Clean water is essential for good health. Without clean water, people can get very sick from diseases like cholera and typhoid. These diseases kill thousands of people every year, especially children under five years old.\n\nIn Côte d'Ivoire, many people in rural areas do not have access to clean water. They must walk long distances to find water, and this water is often not safe to drink. Women and girls spend many hours each day collecting water instead of going to school or working.\n\nWhen communities have access to clean water, health improves, children attend school more regularly, and families can spend more time on productive activities.",gloss:[{w:"essential",d:"absolutely necessary"},{w:"rural",d:"relating to the countryside"},{w:"productive",d:"achieving good results"}],qs:[{q:"What diseases can dirty water cause?",opts:["Malaria and HIV","Cholera and typhoid","Diabetes and cancer","Flu and cold"],ans:1},{q:"Who spends hours collecting water?",opts:["Men and boys","Women and girls","Only children","Only women"],ans:1},{q:"What happens when communities get clean water?",opts:["Nothing changes","Health improves and children attend school","People become richer immediately","Diseases disappear completely"],ans:1}]},
  {id:"rb03",title:"Mobile Phones in Africa",topic:"Technology",passage:"Mobile phones have changed life in Africa in many ways. Today, more people in Africa have mobile phones than have bank accounts or electricity. This shows how quickly the technology has spread.\n\nMobile phones help farmers check market prices before selling their crops. They help families send money to relatives in other cities. They also help people access health information and educational resources.\n\nHowever, mobile phones also have disadvantages. Some people spend too much time on social media instead of working or studying. Young people especially can become addicted to their phones, which affects their concentration and school results.",gloss:[{w:"bank account",d:"a record of money kept at a bank"},{w:"crops",d:"plants grown by farmers for food"},{w:"addicted",d:"unable to stop doing something"}],qs:[{q:"What do more Africans have than bank accounts?",opts:["Cars","Mobile phones","Computers","Televisions"],ans:1},{q:"How do mobile phones help farmers?",opts:["They grow crops faster","They check market prices","They find water","They build houses"],ans:1},{q:"What is a disadvantage of mobile phones?",opts:["They are too expensive","People spend too much time on social media","They don't work in Africa","They cause diseases"],ans:1}]},
  {id:"rb04",title:"The Importance of Reading",topic:"Literacy",passage:"Reading is one of the best habits a student can develop. When you read regularly, your vocabulary grows, your writing improves, and your ability to understand complex ideas becomes stronger.\n\nMany successful people say that reading changed their lives. They read books, newspapers, and articles every day. This helped them learn about the world and develop new ideas.\n\nExperts recommend reading for at least 30 minutes every day. This does not have to be a difficult academic text. You can read a novel, a newspaper, or even a magazine. The important thing is to make reading a daily habit.",gloss:[{w:"habit",d:"something you do regularly"},{w:"vocabulary",d:"all the words you know"},{w:"complex",d:"difficult and involving many parts"}],qs:[{q:"What happens when you read regularly?",opts:["You become tired","Your vocabulary grows and writing improves","You forget quickly","You learn only grammar"],ans:1},{q:"How long do experts recommend reading each day?",opts:["1 hour","15 minutes","30 minutes","2 hours"],ans:2},{q:"What type of text should you read?",opts:["Only academic texts","Only novels","Any text — novels, newspapers, magazines","Only textbooks"],ans:2}]},
  {id:"rb05",title:"Forests and Climate",topic:"Environment",passage:"Forests cover about 31% of the Earth's land surface. They are home to more than half of all plant and animal species on Earth. Forests also absorb carbon dioxide and produce oxygen, which makes them essential for life.\n\nHowever, forests around the world are disappearing at an alarming rate. Every year, millions of hectares of forest are cut down for farming, timber, and construction. This is called deforestation.\n\nDeforestation has serious consequences. It causes soil erosion, reduces rainfall, and contributes to climate change. In West Africa, including Côte d'Ivoire, forests have been greatly reduced in the past 50 years.",gloss:[{w:"absorb",d:"to take in or soak up"},{w:"deforestation",d:"cutting down forests"},{w:"soil erosion",d:"when rain or wind removes the top layer of soil"}],qs:[{q:"What percentage of Earth's land do forests cover?",opts:["15%","50%","31%","75%"],ans:2},{q:"What is deforestation?",opts:["Planting new trees","Cutting down forests","Protecting wildlife","Growing crops"],ans:1},{q:"Which is NOT a consequence of deforestation?",opts:["Soil erosion","Reduced rainfall","More oxygen","Climate change"],ans:2}]},
  {id:"rb06",title:"Women and Work",topic:"Society",passage:"In many countries, women still face inequality in the workplace. They are paid less than men for doing the same work, and they are less likely to be promoted to senior positions. This is called the gender pay gap.\n\nIn Côte d'Ivoire, women make up more than 50% of the population but hold fewer leadership positions in business and government. However, this is slowly changing as more women complete university education and enter professional careers.\n\nResearch shows that companies with more women in leadership positions perform better financially. This suggests that gender equality is not just a moral issue — it is also good for business.",gloss:[{w:"inequality",d:"unfair difference in treatment"},{w:"promoted",d:"given a higher position at work"},{w:"gender pay gap",d:"difference in pay between men and women"}],qs:[{q:"What is the gender pay gap?",opts:["Men earning more than women","Women working more than men","Equal pay for all","Pay based on education"],ans:0},{q:"What percentage of Côte d'Ivoire's population are women?",opts:["More than 50%","About 30%","Exactly 50%","Less than 40%"],ans:0},{q:"Why is gender equality good for business?",opts:["Women work harder","Companies with women leaders perform better financially","It reduces taxes","Women are cheaper to hire"],ans:1}]},
  {id:"rb07",title:"Food and Nutrition",topic:"Health",passage:"Good nutrition is essential for good health, especially for children and young people. A balanced diet includes proteins, carbohydrates, fats, vitamins, and minerals. Each of these nutrients plays an important role in keeping the body healthy.\n\nIn many parts of Africa, malnutrition remains a serious problem. Some children do not get enough food, while others eat too much unhealthy food. Both of these situations can lead to health problems.\n\nExperts recommend eating plenty of fruits and vegetables, reducing sugar and salt, and drinking enough water every day. Traditional African foods, such as yam, plantain, and beans, are often nutritious and affordable.",gloss:[{w:"nutrition",d:"the process of eating the right food"},{w:"malnutrition",d:"poor health caused by lack of proper food"},{w:"nutritious",d:"containing substances needed for good health"}],qs:[{q:"What does a balanced diet include?",opts:["Only vegetables","Proteins, carbohydrates, fats, vitamins, minerals","Only proteins and water","Sugar and salt"],ans:1},{q:"What is malnutrition?",opts:["Eating too much","Poor health from lack of proper food","A tropical disease","A type of exercise"],ans:1},{q:"Which traditional African foods are mentioned as nutritious?",opts:["Rice and pasta","Yam, plantain, and beans","Bread and butter","Meat and fish only"],ans:1}]},
  {id:"rb08",title:"Entrepreneurship in Africa",topic:"Economy",passage:"Entrepreneurship means starting and running your own business. In Africa, many young people are choosing to create their own businesses instead of looking for jobs that may not exist.\n\nSmall businesses are the backbone of many African economies. They create jobs, provide goods and services, and help communities develop. In Côte d'Ivoire, the cocoa and coffee industries support thousands of small farmers and traders.\n\nHowever, starting a business is not easy. Entrepreneurs face challenges such as lack of money, limited access to banks, and competition. Despite these challenges, many young Africans are finding creative ways to succeed.",gloss:[{w:"entrepreneurship",d:"the activity of starting and running businesses"},{w:"backbone",d:"the most important part of something"},{w:"competition",d:"when businesses try to do better than each other"}],qs:[{q:"What does entrepreneurship mean?",opts:["Working for a company","Starting and running your own business","Studying economics","Working in government"],ans:1},{q:"What industries support small farmers in Côte d'Ivoire?",opts:["Oil and gas","Cocoa and coffee","Technology and phones","Fishing and farming"],ans:1},{q:"What challenges do entrepreneurs face?",opts:["Too many customers","Lack of money and limited bank access","Too much competition from government","No challenges at all"],ans:1}]},
  {id:"rb09",title:"The Internet and Learning",topic:"Technology",passage:"The internet has changed the way people learn. Today, students can access information from anywhere in the world through their phones or computers. Online courses, videos, and articles make learning easier and more accessible.\n\nIn Africa, the number of people using the internet has grown rapidly. Many young people use YouTube to learn new skills, watch educational videos, and access information they cannot find in their local libraries.\n\nHowever, not everyone has equal access to the internet. Students in rural areas often have poor or no internet connection. This creates a digital divide between students in cities and those in rural communities.",gloss:[{w:"accessible",d:"easy to reach or use"},{w:"digital divide",d:"the gap between those who have internet access and those who don't"},{w:"rapidly",d:"very quickly"}],qs:[{q:"How has the internet changed learning?",opts:["Made it harder","Made information accessible from anywhere","Replaced schools completely","Made books unnecessary"],ans:1},{q:"What do young Africans use YouTube for?",opts:["Only entertainment","Learning new skills and watching educational videos","Shopping online","Playing games"],ans:1},{q:"What is the digital divide?",opts:["A type of computer","Gap between internet users and non-users","A broken internet connection","A social media platform"],ans:1}]},
  {id:"rb10",title:"African Music and Identity",topic:"Culture",passage:"Music is an important part of African culture and identity. Every region of Africa has its own unique musical traditions, instruments, and styles. From the kora of West Africa to the mbira of Zimbabwe, African music is incredibly diverse.\n\nToday, African music has a global influence. Afrobeats, a genre that originated in Nigeria, is now popular around the world. Artists like Burna Boy and Wizkid have won international awards and performed in some of the world's biggest concert venues.\n\nMusic also plays an important social role. It is used in celebrations, religious ceremonies, and political movements. Many African musicians use their songs to comment on social issues like poverty, inequality, and corruption.",gloss:[{w:"diverse",d:"showing great variety"},{w:"genre",d:"a category of music or art"},{w:"corruption",d:"dishonest behaviour by people in power"}],qs:[{q:"What is the kora?",opts:["A Nigerian food","A West African musical instrument","A Zimbabwean dance","A type of drum"],ans:1},{q:"Where did Afrobeats originate?",opts:["Côte d'Ivoire","South Africa","Nigeria","Ghana"],ans:2},{q:"What social issues do African musicians comment on?",opts:["Only love and relationships","Poverty, inequality, and corruption","Technology and phones","Sport and education"],ans:1}]},
  {id:"rb11",title:"Democracy in Africa",topic:"Politics",passage:"Democracy means that the people of a country choose their leaders through free and fair elections. In a democracy, citizens have the right to vote, to speak freely, and to have their rights protected by law.\n\nMany African countries became democracies after gaining independence in the 1950s and 1960s. However, democracy has not always been stable on the continent. Some countries have experienced military coups, corruption, and election fraud.\n\nDespite these challenges, democracy has grown stronger in many parts of Africa. More elections are now considered free and fair, and more citizens are participating in political processes. Young people especially are becoming more politically active.",gloss:[{w:"elections",d:"a process where people vote to choose leaders"},{w:"military coup",d:"when the army takes control of the government"},{w:"fraud",d:"dishonest actions to deceive people"}],qs:[{q:"What does democracy mean?",opts:["Rule by the army","People choosing leaders through elections","One person ruling forever","Rich people making decisions"],ans:1},{q:"When did many African countries become democracies?",opts:["1900s","1980s","1950s and 1960s","2000s"],ans:2},{q:"What challenges has democracy faced in Africa?",opts:["Too many elections","Military coups, corruption, and fraud","Too much freedom","Lack of candidates"],ans:1}]},
  {id:"rb12",title:"Exercise and Mental Health",topic:"Health",passage:"Exercise is not only good for the body — it is also very good for the mind. Research shows that regular physical activity reduces stress, improves mood, and helps people sleep better. Students who exercise regularly tend to perform better in exams.\n\nWhen we exercise, our bodies release chemicals called endorphins. These chemicals make us feel happy and reduce feelings of anxiety and depression. Even a 20-minute walk can improve your mood significantly.\n\nExperts recommend at least 30 minutes of moderate exercise most days of the week. This can include walking, cycling, swimming, or playing a sport. The important thing is to find an activity you enjoy and do it regularly.",gloss:[{w:"mood",d:"how you feel emotionally"},{w:"endorphins",d:"chemicals in the body that create feelings of happiness"},{w:"moderate",d:"not too much and not too little"}],qs:[{q:"What do endorphins do?",opts:["Make us tired","Make us feel happy and reduce anxiety","Cause pain","Help us sleep"],ans:1},{q:"How long should you walk to improve your mood?",opts:["1 hour","5 minutes","20 minutes","2 hours"],ans:2},{q:"How much exercise do experts recommend?",opts:["1 hour every day","30 minutes most days","Only on weekends","2 hours a week"],ans:1}]},
  {id:"rb13",title:"Cocoa and Côte d'Ivoire",topic:"Economy",passage:"Côte d'Ivoire is the world's largest producer of cocoa beans. Cocoa is the main ingredient in chocolate, and about 40% of the world's cocoa comes from this small West African country. The cocoa industry employs more than one million farmers.\n\nHowever, despite producing so much cocoa, many Ivorian farmers remain poor. The price of cocoa is set by international markets, and farmers often receive only a small fraction of the final price of chocolate in European shops.\n\nThe government has tried to help farmers by setting minimum prices and encouraging the processing of cocoa locally. If Côte d'Ivoire could produce and sell more finished chocolate products, farmers would earn more money.",gloss:[{w:"producer",d:"someone who grows or makes something"},{w:"fraction",d:"a small part of something"},{w:"processing",d:"treating raw materials to make finished products"}],qs:[{q:"What percentage of world cocoa comes from Côte d'Ivoire?",opts:["10%","40%","60%","25%"],ans:1},{q:"Why do farmers earn little despite producing cocoa?",opts:["They are lazy","Prices are set by international markets","There is too much cocoa","Chocolate is not popular"],ans:1},{q:"What has the government tried to do?",opts:["Stop cocoa farming","Set minimum prices and encourage local processing","Sell cocoa to China","Replace cocoa with coffee"],ans:1}]},
  {id:"rb14",title:"Plastic Pollution",topic:"Environment",passage:"Plastic pollution is one of the most serious environmental problems in the world today. Every year, millions of tonnes of plastic end up in rivers, oceans, and on land. This plastic takes hundreds of years to break down.\n\nIn many African cities, including Abidjan, plastic waste is a major problem. Plastic bags block drains, which causes flooding during the rainy season. Plastic in rivers and the ocean harms fish and other wildlife.\n\nSome countries have taken action. Rwanda banned plastic bags in 2008 and is now considered one of the cleanest countries in Africa. Côte d'Ivoire has also introduced some restrictions on plastic bags in recent years.",gloss:[{w:"pollution",d:"damage to the environment by harmful substances"},{w:"break down",d:"to decompose or fall apart"},{w:"restrictions",d:"rules that limit what you can do"}],qs:[{q:"How long does plastic take to break down?",opts:["10 years","50 years","Hundreds of years","1 year"],ans:2},{q:"What problem do plastic bags cause in cities?",opts:["Air pollution","Blocked drains and flooding","Noise pollution","Traffic problems"],ans:1},{q:"Which country banned plastic bags in 2008?",opts:["Nigeria","Côte d'Ivoire","Ghana","Rwanda"],ans:3}]},
  {id:"rb15",title:"Libraries and Knowledge",topic:"Education",passage:"Libraries are important places for learning and research. They provide access to books, newspapers, academic journals, and computers. For many students, the library is the only place where they can find the resources they need for their studies.\n\nIn many African universities, libraries are under-resourced. There are not enough books, and many of the books available are out of date. Internet access is often slow or unavailable. This makes research difficult for students.\n\nHowever, digital libraries are beginning to change this situation. Online databases give students access to millions of academic articles from around the world. Some universities in Africa are investing in digital resources to help their students compete at an international level.",gloss:[{w:"academic journals",d:"publications containing research articles"},{w:"under-resourced",d:"not having enough resources"},{w:"databases",d:"organised collections of information stored on computers"}],qs:[{q:"What do libraries provide access to?",opts:["Only books","Books, newspapers, journals, and computers","Only computers","Only newspapers"],ans:1},{q:"What is a problem with African university libraries?",opts:["Too many students","Under-resourced with outdated books","Too expensive","Too far from students"],ans:1},{q:"What is changing the library situation?",opts:["New buildings","Digital libraries and online databases","More government funding","International donations"],ans:1}]},
  {id:"rb16",title:"Child Labour",topic:"Society",passage:"Child labour means making children work instead of going to school. This is a serious problem in many parts of the world, including parts of Africa. Children who work instead of studying miss out on education and the opportunities it provides.\n\nIn West Africa, child labour is common in cocoa farming. Children as young as ten years old work on farms, sometimes in dangerous conditions. International organisations and governments are working to end this practice.\n\nEducation is the best solution to child labour. When families have enough money and schools are accessible, children are more likely to attend school instead of working.",gloss:[{w:"labour",d:"physical work"},{w:"accessible",d:"easy to reach"},{w:"organisations",d:"groups of people working together for a purpose"}],qs:[{q:"What does child labour mean?",opts:["Children playing","Children working instead of going to school","Children studying","Children travelling"],ans:1},{q:"Where is child labour common in West Africa?",opts:["Fishing industry","Cocoa farming","Technology sector","Schools"],ans:1},{q:"What is the best solution to child labour?",opts:["More police","Education and school access","Stricter laws alone","International pressure"],ans:1}]},
  {id:"rb17",title:"Solar Energy in Africa",topic:"Environment",passage:"Africa receives more sunlight than almost any other part of the world. This makes solar energy a perfect solution for Africa's energy problems. Solar panels can generate electricity even in remote areas where there are no power lines.\n\nIn recent years, the cost of solar panels has dropped significantly. This makes solar energy more affordable for families and businesses. In some parts of Africa, solar energy is already cheaper than electricity from the national grid.\n\nCountries like Kenya, Morocco, and South Africa are leading the way in solar energy. If more African countries invest in solar power, millions of people who currently live without electricity could get access to clean, affordable energy.",gloss:[{w:"generate",d:"to produce electricity"},{w:"remote",d:"far from towns and cities"},{w:"grid",d:"the network of power lines and electricity supply"}],qs:[{q:"Why is solar energy suitable for Africa?",opts:["Africa is cold","Africa receives lots of sunlight","Solar panels are free","Africa has no electricity"],ans:1},{q:"What has happened to the cost of solar panels?",opts:["Increased significantly","Stayed the same","Dropped significantly","Doubled"],ans:2},{q:"Which countries lead in solar energy?",opts:["Nigeria, Ghana, Senegal","Kenya, Morocco, South Africa","Egypt, Libya, Tunisia","Angola, Zambia, Zimbabwe"],ans:1}]},
  {id:"rb18",title:"Traditional Medicine",topic:"Health",passage:"Traditional medicine has been used in Africa for thousands of years. Healers use plants, roots, and other natural substances to treat illnesses. Many people in Africa still rely on traditional medicine, especially in rural areas where hospitals are far away.\n\nSome traditional remedies have been proven effective by modern science. For example, the plant artemisinin, which was used in traditional Chinese medicine, is now used to treat malaria. Scientists are studying many African plants to see if they can be used in modern medicines.\n\nHowever, not all traditional remedies are safe or effective. Some can be harmful if used incorrectly. Health experts recommend combining traditional medicine with modern healthcare for the best results.",gloss:[{w:"healers",d:"people who treat illness using traditional methods"},{w:"remedies",d:"treatments for illness"},{w:"artemisinin",d:"a plant-based medicine used to treat malaria"}],qs:[{q:"What do traditional healers use?",opts:["Modern drugs","Plants, roots, and natural substances","Surgery","Injections"],ans:1},{q:"What is artemisinin used for?",opts:["Treating cancer","Treating malaria","Treating diabetes","Treating heart disease"],ans:1},{q:"What do health experts recommend?",opts:["Only traditional medicine","Only modern medicine","Combining traditional and modern healthcare","Avoiding both"],ans:2}]},
  {id:"rb19",title:"Sports and Development",topic:"Society",passage:"Sport plays an important role in the development of young people. Through sport, young people learn teamwork, discipline, and how to handle success and failure. These skills are valuable in school, work, and life.\n\nIn Côte d'Ivoire, football is the most popular sport. The national team, known as the Elephants, has qualified for three FIFA World Cups. Players like Didier Drogba became international stars and inspired millions of young Ivorians.\n\nSport can also be used as a tool for social development. Sports programmes in disadvantaged communities help keep young people away from crime and give them positive goals to work towards.",gloss:[{w:"discipline",d:"the ability to control your behaviour and work hard"},{w:"qualified",d:"successfully passed the requirements to participate"},{w:"disadvantaged",d:"not having the same opportunities as others"}],qs:[{q:"What do young people learn through sport?",opts:["Only physical fitness","Teamwork, discipline, and handling success and failure","Only competition","How to earn money"],ans:1},{q:"What is the Ivorian national football team called?",opts:["The Lions","The Eagles","The Elephants","The Panthers"],ans:2},{q:"How can sport help disadvantaged communities?",opts:["By making people rich","Keeping youth from crime and giving positive goals","By replacing education","By providing jobs directly"],ans:1}]},
  {id:"rb20",title:"Immigration and Identity",topic:"Society",passage:"Many people around the world leave their home countries to find better opportunities elsewhere. This movement of people is called immigration. Immigrants often face many challenges, including learning a new language, adapting to a new culture, and finding work.\n\nAfrica has its own patterns of immigration. Many Africans migrate within the continent, moving from rural areas to cities or from one country to another in search of work. Others migrate to Europe or other parts of the world.\n\nImmigration raises important questions about identity. When people leave their home country, they must balance their original culture with the new culture of their adopted country. Many immigrants describe feeling between two worlds.",gloss:[{w:"immigration",d:"moving to live permanently in another country"},{w:"migrate",d:"to move from one place to another"},{w:"adopted country",d:"the new country where an immigrant lives"}],qs:[{q:"What is immigration?",opts:["Visiting another country","Moving permanently to another country","Working in another country temporarily","Studying abroad"],ans:1},{q:"Where do many African migrants go within Africa?",opts:["From cities to villages","From rural areas to cities or other countries","Only to Europe","Only to South Africa"],ans:1},{q:"What challenge does immigration raise about identity?",opts:["Learning mathematics","Balancing original and new culture","Finding food","Learning to drive"],ans:1}]},
  {id:"rb21",title:"Urban Growth in Africa",topic:"Society",passage:"Africa is urbanising faster than any other continent. Every year, millions of people move from rural areas to cities in search of jobs, education, and better living conditions. By 2050, it is estimated that more than half of Africa's population will live in cities.\n\nThis rapid urbanisation creates both opportunities and challenges. Cities offer more jobs, better schools, and access to healthcare. However, rapid growth also causes problems such as traffic congestion, pollution, housing shortages, and pressure on water and electricity supplies.\n\nAbidjan, the economic capital of Côte d'Ivoire, is one of the fastest growing cities in West Africa. Managing this growth wisely will be one of the biggest challenges for the country in the coming decades.",gloss:[{w:"urbanising",d:"becoming more urban; more people living in cities"},{w:"congestion",d:"too many vehicles causing slow movement"},{w:"shortage",d:"not enough of something"}],qs:[{q:"How fast is Africa urbanising compared to other continents?",opts:["The slowest","Average speed","The fastest","Same as Asia"],ans:2},{q:"What percentage of Africans will live in cities by 2050?",opts:["25%","More than 50%","75%","Exactly 50%"],ans:1},{q:"What problems does rapid urbanisation cause?",opts:["Too many schools","Congestion, pollution, and housing shortages","Too many hospitals","Lower crime rates"],ans:1}]},
];

export const MISTAKES_BEGINNER = [
  {id:"mb01",title:"'Go to' vs 'Go at'",fr:"Je vais à l'école",wrong:"I go at school every day.",right:"I go to school every day.",rule:"In English, movement verbs (go, come, travel, return, move) are followed by 'to' before place names — not 'at'. French 'a l'ecole' uses 'a', which resembles 'at', but the English preposition for movement towards a place is 'to'. 'At' in English indicates static location (being at a place already): 'I am AT school' (I am currently there) vs 'I go TO school' (I move towards it each day). This fundamental distinction between location ('at') and direction ('to') must be memorised.",ex:[{w:"She goes at university.",r:"She goes to university."},{w:"We went at the hospital.",r:"We went to the hospital."}]},
  {id:"mb02",title:"'Make' vs 'Do' (basics)",fr:"Faire ses devoirs",wrong:"I did a mistake in my exercise.",right:"I made a mistake in my exercise.",rule:"The make/do distinction is one of the most challenging for French speakers because French uses 'faire' for both. General pattern: MAKE is used when something is created or results from an action — make a mistake, make a decision, make an effort, make progress, make a noise, make a suggestion, make a contribution. DO is used for tasks, activities, and processes — do homework, do exercises, do research, do your best, do business, do sport. There is no simple translation rule from French 'faire' — learn these as fixed collocations.",ex:[{w:"She did a good decision.",r:"She made a good decision."},{w:"He is doing a noise.",r:"He is making a noise."}]},
  {id:"mb03",title:"'Since' vs 'For'",fr:"Depuis combien de temps",wrong:"I study English since three years.",right:"I have been studying English for three years.",rule:"This error involves two problems: wrong tense and wrong preposition. SINCE + a specific point in time (since 2020, since Monday, since childhood) indicates when an action started. FOR + a duration (for three years, for six months, for a long time) indicates how long an action has lasted. Both require present perfect in English because the action started in the past and continues to the present. French uses present simple with 'depuis', but English requires the present perfect tense: 'I have been studying', not 'I study'.",ex:[{w:"She works here since Monday.",r:"She has been working here since Monday."},{w:"He is sick since two days.",r:"He has been sick for two days."}]},
  {id:"mb04",title:"Double Negatives",fr:"Je ne sais rien",wrong:"I don't know nothing about this topic.",right:"I don't know anything about this topic.",rule:"English grammar has an absolute rule against double negatives: if a sentence contains a negative word (don't, not, never, nobody, nothing, nowhere), no second negative element is permitted. French regularly combines two negatives ('je ne sais rien', 'personne n'est venu'), but English allows only one: 'I don't know anything' OR 'I know nothing' — never both together. In formal academic writing, avoid contracted negatives ('don't', 'can't') and write the full forms: 'do not' and 'cannot'.",ex:[{w:"She hasn't done nothing.",r:"She hasn't done anything."},{w:"Nobody doesn't understand.",r:"Nobody understands."}]},
  {id:"mb05",title:"'Assist' vs 'Attend'",fr:"Assister à un cours",wrong:"I assisted the English lecture yesterday.",right:"I attended the English lecture yesterday.",rule:"This is one of the most important false friends for French speakers. French 'assister a' means 'to be present at an event', but English 'assist' means 'to help someone'. The correct English word is 'attend'. Saying 'I assisted the conference' implies you helped organise it — not that you were a participant in the audience. Always use 'attend' for events, lectures, ceremonies, weddings, and meetings. Reserve 'assist' exclusively for helping a person directly: 'I assisted the professor with her research.'",ex:[{w:"She assisted the conference.",r:"She attended the conference."},{w:"All students must assist the ceremony.",r:"All students must attend the ceremony."}]},
  {id:"mb06",title:"Uncountable Nouns",fr:"Des informations / Des conseils",wrong:"She gave me some informations and good advices.",right:"She gave me some information and good advice.",rule:"French pluralises these nouns normally ('des informations', 'des conseils', 'des meubles'), which directly causes the -s error in English. In English, information, advice, furniture, equipment, luggage, news, research, and progress are uncountable — they cannot be pluralised under any circumstances. To refer to a single item, use 'a piece of': 'a piece of advice', 'a piece of information', 'an item of furniture'. In academic writing, these words are used constantly and getting them right immediately signals proficiency.",ex:[{w:"The news are very bad today.",r:"The news is very bad today."},{w:"I need some furnitures for my room.",r:"I need some furniture for my room."}]},
  {id:"mb07",title:"'Actually' ≠ 'Actuellement'",fr:"Actuellement je suis étudiant",wrong:"Actually, I am a student at UPGC.",right:"Currently, I am a student at UPGC.",rule:"'Actually' is a serious false friend that causes genuine communication problems. In English, 'actually' means 'in reality' or 'in fact' — it is used to correct a misunderstanding or add a surprising truth: 'He looks young, but he is actually 45.' It does NOT mean 'at this time' or 'at present'. For the French 'actuellement', always use: currently, at present, at the moment, nowadays, at this stage, or right now. In professional and academic contexts, this error can completely mislead the reader or listener.",ex:[{w:"Actually, the president lives in Abidjan.",r:"Currently, the president lives in Abidjan."},{w:"He actually studies in France.",r:"He is currently studying in France."}]},
  {id:"mb08",title:"'Interested in' not 'Interested by'",fr:"Intéressé par",wrong:"I am very interested by this subject.",right:"I am very interested in this subject.",rule:"The collocation 'interested in' is fixed — the preposition 'in' cannot be replaced by 'by', 'about', or 'of'. French 'interesse par' suggests 'by', which is why this error is so frequent among French speakers. Other fixed adjective-preposition collocations that differ from French: good AT, responsible FOR, afraid OF, different FROM, similar TO, dependent ON, capable OF, aware OF, satisfied WITH. None of these can be reliably deduced from French — they must be learned individually as fixed units.",ex:[{w:"She is interested by mathematics.",r:"She is interested in mathematics."},{w:"Are you interested by the job?",r:"Are you interested in the job?"}]},
  {id:"mb09",title:"'Depend on' not 'Depend of'",fr:"Dépendre de",wrong:"The result depends of your effort.",right:"The result depends on your effort.",rule:"'Depend' is invariably followed by 'on' in English — no other preposition is possible. French 'dependre de' maps to 'depend of' in direct translation, but this is incorrect. Other verbs with fixed prepositions that differ from French: rely on, insist on, focus on, agree with, comply with, result from, contribute to, refer to, apply to, account for. These cannot be derived from French equivalents and must be memorised as complete units (verb + preposition together).",ex:[{w:"Success depends of hard work.",r:"Success depends on hard work."},{w:"It depends of the weather.",r:"It depends on the weather."}]},
  {id:"mb10",title:"Verb after Modal",fr:"Je peux parler anglais",wrong:"She can to speak English very well.",right:"She can speak English very well.",rule:"Modal verbs (can, will, must, should, may, might, could, would, shall) are followed directly by the base verb — never by 'to'. This is a defining grammatical property of English modal verbs. French equivalents ('pouvoir', 'devoir', 'vouloir') are ordinary verbs that combine with infinitives using 'de' or 'a', leading to the error 'can to speak'. English modals have no such connector. The only apparent exception is 'ought to', which always includes 'to': 'She ought to study harder.' All other modals: modal + base verb with no 'to'.",ex:[{w:"You must to study for the exam.",r:"You must study for the exam."},{w:"He will to come tomorrow.",r:"He will come tomorrow."}]},
  {id:"mb11",title:"'Say' vs 'Tell'",fr:"Dire / Raconter",wrong:"She told that the exam was difficult.",right:"She said that the exam was difficult.",rule:"SAY and TELL follow systematically different grammatical patterns. TELL requires an indirect object — a person directly after it: tell me, tell him, tell the students (you tell SOMEONE something). SAY does not take a person directly — you say something, and optionally say something TO someone. Reporting speech: 'She told me that she was coming' and 'She said that she was coming' are both correct. But 'She told that she was coming' is wrong (no person after 'tell'), and 'She said me that she was coming' is wrong (person after 'say' requires 'to').",ex:[{w:"He said me that he was tired.",r:"He told me that he was tired."},{w:"She told that she was coming.",r:"She said that she was coming."}]},
  {id:"mb12",title:"Future Plans",fr:"Je vais faire ça demain",wrong:"I study tonight instead of going out.",right:"I am going to study tonight instead of going out.",rule:"Using present simple for a personal future plan ('I study tonight') makes it sound like a habitual, recurring action. For personal plans and intentions decided before the moment of speaking, use GOING TO + base verb. For fixed arrangements with other people, use PRESENT CONTINUOUS. For spontaneous decisions and predictions, use WILL. Present simple with future meaning is only appropriate for timetabled events: 'The exam starts at 9am' (a scheduled event on a timetable). For personal intentions: 'I am going to study tonight.'",ex:[{w:"She travels to Abidjan tomorrow.",r:"She is going to travel to Abidjan tomorrow."},{w:"We eat together this evening.",r:"We are going to eat together this evening."}]},
  {id:"mb13",title:"'Married with' vs 'Married to'",fr:"Marié avec",wrong:"She is married with a doctor.",right:"She is married to a doctor.",rule:"'Married to' is the only correct preposition collocation in English — 'married with' does not exist. French 'marie avec' uses 'avec' (with), which students translate directly — but English requires 'to'. For the action of getting married: 'She got married to a doctor' (not 'with'). Other relationship prepositions that differ from French: 'engaged to' (fionce de), 'related to', 'associated with', 'connected to'. Preposition collocations in English cannot be reliably predicted from French equivalents — they must be learned case by case.",ex:[{w:"He got married with his colleague.",r:"He got married to his colleague."},{w:"They have been married with each other for 10 years.",r:"They have been married to each other for 10 years."}]},
  {id:"mb14",title:"Comparative Form",fr:"Plus intelligent que",wrong:"English is more easy than mathematics for me.",right:"English is easier than mathematics for me.",rule:"Comparative formation follows a strict rule based on word length. SHORT adjectives (one syllable, or two syllables ending in -y, -er, -le, -ow): add -er — easy-easier, happy-happier, tall-taller, big-bigger (double final consonant). LONG adjectives (three or more syllables, most two-syllable adjectives): use 'more' — more important, more significant, more interesting. French always uses 'plus' regardless of length ('plus facile', 'plus interessant'), so French speakers default to 'more' for all adjectives, causing this error.",ex:[{w:"She is more tall than her sister.",r:"She is taller than her sister."},{w:"This exercise is more hard than yesterday's.",r:"This exercise is harder than yesterday's."}]},
  {id:"mb15",title:"'Possibility' vs 'Possibly'",fr:"Il est possible que",wrong:"It is possible that she will comes tomorrow.",right:"It is possible that she will come tomorrow.",rule:"After any modal verb (will, can, must, should, may, might, could, would), the following verb MUST be in base form — no -s, no -ed, no -ing ending. The modal verb already carries all information about tense, aspect, and obligation; the base verb following it adds no further grammatical marking. 'Will comes' incorrectly adds third-person -s as if 'comes' were an independent main verb. This rule applies to all modal verbs, for all subjects (he/she/it/they/we/I), with no exceptions whatsoever.",ex:[{w:"He will arrives at 9am.",r:"He will arrive at 9am."},{w:"She might goes to the library.",r:"She might go to the library."}]},
  {id:"mb16",title:"'Prefer' + Gerund",fr:"Je préfère lire",wrong:"I prefer to reading novels over watching films.",right:"I prefer reading novels to watching films.",rule:"'Prefer' can be followed by a gerund or infinitive, but when comparing two things, the required structure is strictly 'prefer X to Y' — not 'prefer X over Y'. French 'preferer X plutot que Y' sometimes leads to 'prefer X over Y' in English, but this is not standard in formal usage. When making a comparison, both items must be in parallel grammatical form: 'I prefer reading to watching' (both gerunds) or 'I prefer to read rather than to watch' (both infinitives). Never mix forms.",ex:[{w:"She prefers to studying alone.",r:"She prefers studying alone."},{w:"He prefers football over to play basketball.",r:"He prefers playing football to playing basketball."}]},
  {id:"mb17",title:"'Borrow' vs 'Lend'",fr:"Emprunter / Prêter",wrong:"Can you borrow me your dictionary?",right:"Can you lend me your dictionary?",rule:"LEND and BORROW describe the same transaction from two opposite perspectives. LEND means to give something temporarily to someone (the item moves away from you): 'Can you lend me your pen?' means give your pen to me. BORROW means to take something temporarily from someone (the item moves towards you): 'Can I borrow your pen?' means may I take it. The crucial error 'Can you borrow me your pen?' uses the wrong word for the wrong perspective. Think: when you LEND, you let something leave you; when you BORROW, you bring something to yourself.",ex:[{w:"Please borrow me your pen.",r:"Please lend me your pen."},{w:"I want to lend a book from the library.",r:"I want to borrow a book from the library."}]},
  {id:"mb18",title:"'Sympathetic' ≠ 'Sympa'",fr:"Il est sympa",wrong:"My professor is very sympathetic.",right:"My professor is very kind / nice / friendly.",rule:"'Sympathetic' is a dangerous false friend that causes real misunderstanding in professional and academic contexts. In English, 'sympathetic' means 'showing compassion and understanding for someone's suffering or misfortune' — NOT 'nice', 'likeable', 'friendly', or 'pleasant'. Saying 'My professor is very sympathetic' implies the professor feels sorry for you because you are suffering or in difficulty. To convey the French meaning of 'sympathique', always use: kind, friendly, approachable, warm, pleasant, or nice. Confusing these in a professional context can cause significant embarrassment.",ex:[{w:"She is a sympathetic person — everyone likes her.",r:"She is a kind/friendly person — everyone likes her."},{w:"The teacher is very sympathetic and helps everyone.",r:"The teacher is very kind and helps everyone."}]},
  {id:"mb19",title:"'Eventually' ≠ 'Éventuellement'",fr:"Éventuellement",wrong:"Eventually, I could help you with that.",right:"Possibly, I could help you with that.",rule:"'Eventually' is one of the most frequently mistranslated words from French into English. In English, 'eventually' means ONLY 'after a long time' or 'in the end' — it refers to something that will definitely happen but only after a delay or a long wait: 'He studied every night and eventually passed.' It carries absolutely no sense of possibility or uncertainty. French 'eventuellement' means 'possibly', 'perhaps', or 'if the occasion arises' — a meaning that is close to the opposite of 'eventually'. Always use possibly, perhaps, maybe, if necessary, or if applicable for the French 'eventuellement'.",ex:[{w:"Eventually, we might visit Paris.",r:"Possibly, we might visit Paris."},{w:"She eventually can come to the meeting.",r:"She might possibly come to the meeting."}]},
  {id:"mb20",title:"Verb Tense after 'If'",fr:"Si je suis libre...",wrong:"If I will be free tomorrow, I will come.",right:"If I am free tomorrow, I will come.",rule:"In first conditional sentences (real and possible future situations), the rule is: IF + present simple (for the condition) + WILL + base verb (for the result). Never place 'will' directly after 'if' in this structure: 'If it rains...' is correct; 'If it will rain...' is wrong. Interestingly, French 'si il pleut' also uses the present tense in the if-clause, so this aspect is actually parallel between the two languages. The error usually occurs when students assume that any future reference requires 'will' throughout the sentence.",ex:[{w:"If it will rain, we will stay inside.",r:"If it rains, we will stay inside."},{w:"If she will study, she will pass.",r:"If she studies, she will pass."}]},
  {id:"mb21",title:"Subject Pronoun Omission",fr:"Il pleut / C'est difficile",wrong:"Is raining outside. Is very cold today.",right:"It is raining outside. It is very cold today.",rule:"English is a subject-prominent language: every finite clause must contain an explicit grammatical subject. Unlike French, where verb endings indicate the person ('pleut' = it rains, without needing an explicit subject), English verb forms do not change to show the grammatical person. When there is no meaningful subject for a sentence about weather, time, distance, or difficulty, English requires the dummy subject 'it': it is raining, it is 3 o'clock, it is far away, it is important. This 'it' does not refer to anything specific — it simply fills the obligatory subject position.",ex:[{w:"Is important to study every day.",r:"It is important to study every day."},{w:"Is difficult to speak English perfectly.",r:"It is difficult to speak English perfectly."}]},
];

